library(shiny)

dx <- function(n, r = 1) {
  ceiling(runif(r) * n)
}

ui <- fluidPage(
  titlePanel("Dice Roller"),
  numericInput("sides", "Number of sides:", 6, min = 2),
  actionButton("roll", "Roll"),
  textOutput("result")
)

server <- function(input, output) {
  observeEvent(input$roll, {
    output$result <- renderText({
      dx(input$sides)
    })
  })
}

shinyApp(ui, server)
